@js:
(function() {
    // 1. 先尝试静态抓取，保留 HTML 标签，避免正文排版被压扁
    var doc = org.jsoup.Jsoup.parse(result);
    var box = doc.select("div.read-content");

    // 去除干扰元素
    box.select("script, style, .ad-block").remove();

    // 关键点：使用 html()，不要使用 text()
    // text() 会把 <br>、<p>、<div> 等排版标签全部压成空格，导致正文挤成一团
    var content = box.html();

    var isInvalid = !content || content.length < 50 ||
                    content.match(/加载中|正在获取|请稍候|爱丽丝书屋/);

    if (!isInvalid) {
        return content;
    }

    // 2. 静态抓取失败时，再使用 WebView 渲染正文区域
    var html = java.webView(result, "div.read-content", "3000");
    var doc2 = org.jsoup.Jsoup.parse(html);
    var box2 = doc2.select("div.read-content");

    // 去除干扰元素
    box2.select("script, style, .ad-block").remove();

    // 同样返回 html()，保留段落和换行排版
    return box2.html();
})();
